INSERT INTO `sys_email` (`ID`, `CODE`, `NAME`, `DESCRIPTION`, `FROM_EMAIL`, `FROM_NAME`, `CC`, `BCC`, `SUBJECT`, `BODY`, `ATTACHMENTS`, `TEMPLATE`, `LAST_USER_ID`, `CREATION_DATE`, `MODIFICATION_DATE`) VALUES
(1, 'X_EMAIL_ACCOUNT_CREATION', 'Creación de Cuenta de Usuario', 'Email de envío de acceso como nuevo usuario del sistema.', 'soporte@empleos.click', 'El equipo de Empleos.Click', NULL, 'yecid.pra@gmail.com;yecid_pra@hotmail.com', 'Creación de su Cuenta de Usuario', '<span style=\"font-family: Arial;\">Hola ~NOMBRE~, te informamos que tu cuenta en el sistema fue creada exitosamente.<br><br>Para acceder debes ingresar al siguiente enlace:<br><br></span><span style=\"font-family: Arial;\"><a target=\"_blank\" href=\"~ACCESS_LINK~\"><span style=\"font-family: Arial;\">~ACCESS_LINK~</span></a><br><br>Tienes un password temporal que deberás cambiar al acceder al sistema, este password es: ~PASSWORD~ <br><br>Agradecemos tu confianza y esperamos brindarte una experiencia agradable.<br><br>Saludos<br><span style=\"font-style: italic;\"><br>El equipo de <a href=\"http://www.empleos.click\">Empleos.Click</a><br></span></span>', NULL, 'generic', 0, '2016-03-08 06:19:49', '0000-00-00 00:00:00'),
(2, 'X_EMAIL_PASSWORD_REQUEST', 'Recuperación de Acceso', 'Es el correo de recuperación de accesos al sistema', 'soporte@empleos.click', 'Soporte Empleos.Click', NULL, 'yecid.pra@gmail.com;yecid_pra@hotmail.com', 'Recuperación de contraseña solicitada', '<span style=\"font-family: Arial;\">Hola ~NOMBRE~, hemos recibido una solicitud de recuperación de contraseña en nuestro sistema.<br><br>Por favor accede al siguiente enlace para recuperar tu acceso al sistema:<br><br></span><span style=\"font-family: Arial;\"><a target=\"_blank\" href=\"~RESET_LINK~\"><span style=\"font-family: Arial;\">~RESET_LINK~</span></a><br><br>Saludos<br><span style=\"font-style: italic;\"><br>El equipo de <a href=\"http://www.empleos.click\" target=\"_blank\">Empleos.Click</a></span></span><br>', NULL, 'generic', 0, '2016-03-09 00:57:39', '0000-00-00 00:00:00'),
(3, 'J_EMAIL_SUBSCRIPTION_INITIAL', 'Suscripción de Usuario', 'Correo de bienvenida al portal de empleos.\r\n\r\nEl Equipo de Empleos.Click', 'soporte@empleos.click', 'El equipo de Empleos.Click', NULL, 'yecid.pra@gmail.com; raul.ehb@gmail.com;', 'Bienvenida a Empleos.Click', 'Hola ~NOMBRE_SIMPLE~,<br><br>Gracias por suscribirte en <a href=\"https://www.empleos.click\" target=\"_blank\">Empleos.Click</a> , el portal de empleos mas moderno y preferido.<br><br>Te estaremos enviando periódicamente información con los requerimientos que vayan apareciendo relacionados a <span style=\"font-weight: bold;\">~FORMACION~</span>.<br><br>Muy pronto estaremos con más sorpresas y oportunidades mejoradas de trabajo.<br><br>Gracias por tu confianza y preferencia.<br><br>Saludos<br><br>El equipo de Empleos.Click<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br><table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\"><div><span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.clic\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n<div> </div>\r\n</div>\r\n</div>', NULL, 'generic', 0, '2016-04-10 00:19:16', '0000-00-00 00:00:00'),
(4, 'J_EMAIL_NOTIFICATION_SUBSCRIBE', 'Notificaciön a Suscriptor', 'Correo de requerimientos de personal como Notificaciön a Suscriptor. El Equipo de Empleos.Click', 'info@empleos.click', 'El equipo de Empleos.Click', NULL, 'empleos.click@gmail.com', 'Requerimientos de Personal', 'Hola ~NOMBRE~,<br><br>Hace poco te suscribiste en <a href=\"https://www.empleos.click\" target=\"_blank\">Empleos.Click</a> , el portal de empleos mas moderno y preferido.<br><br>Te informamos sobre nuevas oportunidades laborales que podrían resultarte de interés. ~FRASE_DETALLE~:<br><br>~DETALLE_AVISOS~<br><br><br>También puedes revisar muchos mas requerimientos de personal vigentes en tu portal  <a href=\"https://www.empleos.click\" target=\"_blank\">www.Empleos.Click</a> , donde encontrarás más de un centenar de anuncios vigentes.<br><br><br>Nuevamente gracias por tu preferencia.<br><br>Saludos<br><br>El equipo de Empleos.Click<br><img style=\"width: 181px;\" src=\"https://www.empleos.click/img/Logo-Mail-Empleos-Click.png\"><br><table class=\"table table-bordered\" style=\"min-width:590px;background-color:#1b85aa;border-color:#1b85aa;\"><tbody><tr><td><br></td></tr></tbody></table>\r\n\r\n<div style=\"font-size:14px;color:#919191;font-weight:normal;text-align:center;font-family:\'Arial\',Helvetica,sans-serif\"><div><span style=\"color:#bcbec0\">Síguenos en facebook <a href=\"http://www.facebook.comT/empleos.clic\" target=\"_blank\">https://www.facebook.com/empleos.click</a></span>\r\n<div><span style=\"color:#bcbec0\">Recibiste este correo por una solicitud realizada hace poco.</span></div>\r\n<div> </div>\r\n</div>\r\n</div>', NULL, 'generic', 0, '2017-11-22 03:15:38', '0000-00-00 00:00:00');
